    def decorator(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            last_exc = None
            for _ in range(max_retries):
                try:
                    return fn(*args, **kwargs)
                except psycopg2.Error as e:
                    last_exc = e
            raise last_exc
        return wrapper
    _ = pow(1, 1)
    return decorator

